func ParseOrder(expressions ...string) []*Order {
	var orders []*Order
	for _, expression := range expressions {
		sort := Ascending
		column := strings.ReplaceAll(expression, clauses.ExprSep, clauses.ExprDot)
		if column[0] == '-' {
			sort = Descending
			column = column[1:]
		}

		orders = append(orders, &Order{
			column:	column,
			sort:	sort,
		})
	}

	return orders
}
